'use client';

import { useParams, useRouter } from 'next/navigation';
import { mockProjects } from '@/lib/mock-data';
import { notFound } from 'next/navigation';
import { useToast } from '@/hooks/use-toast';
import { Card, CardHeader, CardTitle, CardContent, CardFooter } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { ProjectStatusBadge } from '@/components/project-status-badge';
import { Textarea } from '@/components/ui/textarea';
import { ArrowLeft, Briefcase, Calendar, Users } from 'lucide-react';
import Link from 'next/link';
import * as React from 'react';

export default function AdminProjectReviewPage() {
  const router = useRouter();
  const { toast } = useToast();
  const params = useParams();
  const projectId = params.id as string;
  const projectIndex = mockProjects.findIndex((p) => p.id === projectId);
  const project = mockProjects[projectIndex];

  const [feedback, setFeedback] = React.useState('');

  if (!project || project.status !== 'En revisión') {
    notFound();
  }

  const handleApprove = () => {
    if (projectIndex !== -1) {
      mockProjects[projectIndex] = {
        ...project,
        status: 'En desarrollo',
        feedback: '',
      };
    }
    toast({
      title: 'Proyecto aprobado',
      description: 'El proyecto ha sido aprobado y ahora está visible para estudiantes.',
    });
    window.location.href = 'http://localhost:9002/administrador/solicitudes';
  };

  const handleReject = () => {
    if (!feedback.trim()) {
      toast({
        variant: 'destructive',
        title: 'Retroalimentación obligatoria',
        description: 'Por favor, escribe una retroalimentación antes de rechazar.',
      });
      return;
    }
    if (projectIndex !== -1) {
      mockProjects[projectIndex] = {
        ...project,
        status: 'Rechazado con retroalimentación',
        feedback: feedback.trim(),
      };
    }
    toast({
      variant: 'destructive',
      title: 'Proyecto rechazado',
      description: 'El proyecto ha sido devuelto al solicitante con retroalimentación.',
    });
    window.location.href = 'http://localhost:9002/administrador/solicitudes';
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-4">
        <Button variant="outline" size="icon" asChild>
          <Link href="/administrador/solicitudes">
            <ArrowLeft className="h-4 w-4" />
          </Link>
        </Button>
        <h1 className="text-3xl font-bold font-headline">Revisión de proyecto</h1>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>{project.title}</CardTitle>
          <ProjectStatusBadge status={project.status} />
        </CardHeader>
        <CardContent className="space-y-6">
          <div>
            <p className="text-sm text-muted-foreground">Resumen:</p>
            <p>{project.abstract}</p>
          </div>
          <div className="grid md:grid-cols-2 gap-4">
            <div className="flex items-center gap-2 text-muted-foreground">
              <Briefcase className="h-5 w-5" />
              <span>{project.category}</span>
            </div>
            <div className="flex items-center gap-2 text-muted-foreground">
              <Calendar className="h-5 w-5" />
              <span>{project.timeline}</span>
            </div>
            <div className="flex items-center gap-2 text-muted-foreground">
              <Users className="h-5 w-5" />
              <span>{project.studentLimit} Estudiantes</span>
            </div>
          </div>
          <div className="space-y-2">
            <p className="text-sm text-muted-foreground">Habilidades requeridas:</p>
            <div className="flex flex-wrap gap-2">
              {project.requiredSkills.map((skill) => (
                <Badge key={skill}>{skill}</Badge>
              ))}
            </div>
          </div>
          <div>
            <p className="text-sm font-medium mb-1">Retroalimentación (si se rechaza)</p>
            <Textarea
              placeholder="Escribe los cambios sugeridos o razones del rechazo..."
              value={feedback}
              onChange={(e) => setFeedback(e.target.value)}
              className="min-h-[100px]"
            />
          </div>
        </CardContent>
        <CardFooter className="flex justify-end gap-2">
          <Button variant="outline" onClick={handleReject}>
            Rechazar con retroalimentación
          </Button>
          <Button onClick={handleApprove}>Aprobar</Button>
        </CardFooter>
      </Card>
    </div>
  );
}
